const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const strOrEmpty = v => (v === undefined || v === null) ? '' : String(v);
  const phone = strOrEmpty(j.phone);
  const msgId = strOrEmpty(j.msgId);
  const messageType = strOrEmpty(j.messageType).toLowerCase();
  const mediaUrl = strOrEmpty(j.media_url);
  const mediaBase64 = strOrEmpty(j.media_base64);
  const caption = strOrEmpty(j.caption);
  const mimeType = strOrEmpty(j.mimeType);
  const convId = strOrEmpty(j.chatwoot_conversation_id);
  const testRunId = strOrEmpty(j.test_run_id);
  if (!msgId) throw new Error('IGOR_02: msgId is required');
  if (!messageType) throw new Error('IGOR_02: messageType is required');
  let branch;
  if (messageType === 'audio') branch = 'audio';
  else if (messageType === 'image') branch = caption.trim().length > 0 ? 'image_with_caption' : 'image_no_caption';
  else if (messageType === 'document') branch = 'document';
  else if (messageType === 'text') branch = 'text';
  else branch = 'unknown';
  return { json: { phone, msgId, messageType, media_url: mediaUrl, media_base64: mediaBase64, caption, mimeType, chatwoot_conversation_id: convId, test_run_id: testRunId, _branch: branch, _has_media_url: mediaUrl.length > 0, _has_media_base64: mediaBase64.length > 0 } };
});

const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const b64 = String(j.media_base64 || '');
  const mime = String(j.mimeType || 'audio/ogg');
  let ext = 'ogg';
  if (mime.includes('mp3') || mime.includes('mpeg')) ext = 'mp3';
  else if (mime.includes('wav')) ext = 'wav';
  else if (mime.includes('m4a') || mime.includes('mp4')) ext = 'm4a';
  else if (mime.includes('webm')) ext = 'webm';
  const buffer = Buffer.from(b64, 'base64');
  return {
    json: { ...j, _audio_decoded: true, _audio_bytes: buffer.length },
    binary: {
      data: {
        data: b64,
        fileName: 'audio.' + ext,
        mimeType: mime,
        fileExtension: ext
      }
    }
  };
});

