const validated = $('Validate Payload').first().json;
const items = $input.all();
return items.map(item => {
  let base64;
  let mimeType;
  const bin = item.binary && item.binary.data;
  if (bin && bin.data) {
    base64 = String(bin.data);
    mimeType = String(bin.mimeType || validated.mimeType || 'image/png');
  } else if (validated.media_base64) {
    base64 = String(validated.media_base64);
    mimeType = String(validated.mimeType || 'image/png');
  } else {
    throw new Error('IGOR_02 image_no_caption: no binary and no media_base64 to encode');
  }
  const dataUrl = 'data:' + mimeType + ';base64,' + base64;
  return { json: { image_data_url: dataUrl, image_mime_type: mimeType } };
});

