const validated = $('Validate Payload').first().json;
const items = $input.all();
return items.map(item => {
  const resp = item.json || {};
  let descricao = '';
  let tipo = 'outro';
  let safetyFlags = { clinical: false, sensitive_image: false, payment_proof: false, financial: false };
  let parsedOk = false;
  try {
    const choices = Array.isArray(resp.choices) ? resp.choices : [];
    const content = choices.length > 0 && choices[0].message ? String(choices[0].message.content || '') : '';
    if (content) {
      const parsed = JSON.parse(content);
      descricao = String(parsed.descricao || '').trim();
      tipo = String(parsed.tipo || 'outro').trim();
      const sf = parsed.safety_flags || {};
      safetyFlags = {
        clinical: Boolean(sf.clinical),
        sensitive_image: Boolean(sf.sensitive_image),
        payment_proof: Boolean(sf.payment_proof),
        financial: Boolean(sf.financial)
      };
      parsedOk = true;
    }
  } catch (e) {
    descricao = '[imagem nao classificada - parse falhou]';
    safetyFlags = { clinical: false, sensitive_image: false, payment_proof: false, financial: false };
  }
  if (!descricao) descricao = '[imagem sem descricao]';
  let shouldHandoff = false;
  let handoffReason = null;
  if (safetyFlags.clinical) { shouldHandoff = true; handoffReason = 'imagem_clinica_sensivel'; }
  else if (safetyFlags.sensitive_image) { shouldHandoff = true; handoffReason = 'imagem_sensivel'; }
  return {
    json: {
      phone: validated.phone,
      msgId: validated.msgId,
      messageType: validated.messageType,
      chatwoot_conversation_id: validated.chatwoot_conversation_id,
      test_run_id: validated.test_run_id,
      _branch: 'image_no_caption',
      normalized_text: '[imagem] ' + descricao,
      media_summary: descricao,
      safety_flags: safetyFlags,
      safety_flags_json: JSON.stringify(safetyFlags),
      should_handoff: shouldHandoff,
      handoff_reason: handoffReason,
      image_tipo: tipo,
      _vision_parsed_ok: parsedOk
    }
  };
});

const validated = $('Validate Payload').first().json;
const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const extractedText = String(j.text || '');
  const caption = String(validated.caption || '');
  const filename = caption.length > 0 ? caption : '';
  const haystack = (caption + ' ' + filename + ' ' + extractedText).toLowerCase();
  const clinicalRegex = /(exame|laudo|prescri[cç][ãa]o|receita|crm[\-\s]?\d|diagn[oó]stico|hemograma|raio[\s-]?x|ressonancia|tomografia)/i;
  const isClinical = clinicalRegex.test(haystack);
  const textLen = extractedText.length;
  const snippet = extractedText.slice(0, 300);
  const normalizedText = '[documento] ' + (filename || 'arquivo.pdf') + ' (' + textLen + ' chars)';
  const mediaSummary = snippet.length > 0 ? snippet : ('[documento ' + (filename || 'arquivo.pdf') + ']');
  const safetyFlags = { clinical: isClinical, sensitive_image: false, payment_proof: false, financial: false };
  return {
    json: {
      phone: validated.phone,
      msgId: validated.msgId,
      messageType: validated.messageType,
      chatwoot_conversation_id: validated.chatwoot_conversation_id,
      test_run_id: validated.test_run_id,
      _branch: 'document',
      normalized_text: normalizedText,
      media_summary: mediaSummary,
      safety_flags: safetyFlags,
      safety_flags_json: JSON.stringify(safetyFlags),
      should_handoff: isClinical,
      handoff_reason: isClinical ? 'documento_clinico_sensivel' : null,
      document_text_length: textLen
    }
  };
});
